#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int run_command(const char *prog, char *const argv[]) {
    pid_t pid = fork();
    if (pid == -1) {
        perror("fork");
        return -1;
    }
    if (pid == 0) {
        execvp(prog, argv);
        perror("execvp");
        _exit(127); /* convention: 127 = command not found */
    }
    int status;
    waitpid(pid, &status, 0);
    if (WIFEXITED(status))
        return WEXITSTATUS(status);
    return -1;
}

int main(void) {
    int rc;

    char *cmd1[] = {"echo", "Command 1 OK", NULL};
    rc = run_command("echo", cmd1);
    printf("Exit code: %d\n", rc);

    char *cmd2[] = {"test", "-f", "/nonexistent", NULL};
    rc = run_command("test", cmd2);
    printf("Exit code: %d\n", rc);

    char *cmd3[] = {"echo", "Command 3 OK", NULL};
    rc = run_command("echo", cmd3);
    printf("Exit code: %d\n", rc);

    return 0;
}

